  ('aboriginal-f0899a01-moex-00287', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於公權力行政之敘述，下列何者錯誤？', '["公權力得依法規授權私人行使", "係在公法支配下所為之各種行政行為", "私經濟行政亦屬於公權力行政", "其救濟途徑原則上為行政訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "3e47e40b33a1", "answer_pdf_sha1": "28e21bfe5d60", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00288', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於傳統特別權力關係理論，下列敘述何者錯誤？', '["國家可不待法律授權，逕行訂定特別命令拘束義務人", "對於違反特別權力關係內部秩序者，國家可施以懲戒", "當事人發生爭執時須先提申訴，對結果不服時再提起訴訟", "特別權力關係之義務範圍概括且不確定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "3e47e40b33a1", "answer_pdf_sha1": "28e21bfe5d60", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00289', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '依地方制度法規定，關於自治法規之公布與施行，下列敘述何者錯誤？', '["地方行政機關收到自治條例後，除有特別規定外，應於30日內公布", "自治法規須經上級政府核定者，核定機關應於1個月內為決定；逾期未決定者，自治法規失其效力", "自治法規除另有規定外，自公布或發布之日起算至第3日起發生效力", "自治法規依規定應經其他機關核定者，應於核定文送達各該地方行政機關30日內公布或發布"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "3e47e40b33a1", "answer_pdf_sha1": "28e21bfe5d60", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00290', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '甲縣乙鄉丙村長欲在村管理之公園內興建大型村長辦公室，遭村民反對發動罷免去職，所遺任期不足 2年，應由下列何種方式執行村長職務？', '["全村村民補選村長", "鄉公所派員代理村長至任期屆滿", "縣長直接派員擔任村長", "由當屆村長選舉次高票者遞補"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "3e47e40b33a1", "answer_pdf_sha1": "28e21bfe5d60", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
